MAX_STEPS = 15

def governance_node(state):
    steps = state.get('steps', 0)
    cost = state.get('total_cost', 0.0)

    if steps > MAX_STEPS:
        return {"status": "error", "reason": "Step limit exceeded"}

    if cost > 2.50:
        return {"status": "error", "reason": "Budget cap exceeded"}
